import{_ as t,o as r,c as a,ai as o}from"./chunks/framework.DMjte4z8.js";const p=JSON.parse('{"title":"地形纹理与贴图技巧","description":"","frontmatter":{"title":"地形纹理与贴图技巧","category":"terrain","updated":"2026-05-07T00:00:00.000Z","model":"minimax/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://worldofwarcraft.blizzard.com/","https://www.youtube.com/watch?v=E1COCnMUIhQ","https://bentleysystems.service-now.com/community"]},"headers":[],"relativePath":"terrain/地形纹理与贴图技巧.md","filePath":"terrain/地形纹理与贴图技巧.md","lastUpdated":1779351155000}'),n={name:"terrain/地形纹理与贴图技巧.md"};function i(s,e,l,c,d,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="地形纹理与贴图技巧" tabindex="-1">地形纹理与贴图技巧 <a class="header-anchor" href="#地形纹理与贴图技巧" aria-label="Permalink to “地形纹理与贴图技巧”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>地形纹理是决定地图外观的基础元素，它能让一片平淡的绿色&quot;海洋&quot;变成郁郁葱葱的森林、荒芜的沙漠或冰封的冻土。在魔兽争霸3地图编辑器中，<strong>地形纹理（Terrain Texture）</strong> 决定了地面看起来像什么——草地、泥土、岩石、雪地、水面等。本节将教你如何为你的地图选择和涂抹纹理，让你的地图从&quot;毛坯房&quot;变成有灵魂的虚拟世界。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>打开地形纹理面板</strong> — 在世界编辑器（World Editor）顶部菜单栏中点击&quot;地形（Terrain）&quot;选项卡，然后选择&quot;地形纹理（Terrain Texture）&quot;[^1]。这一步会打开纹理工具栏，你会在左侧看到所有可用的地形纹理列表。</p></li><li><p><strong>了解纹理列表</strong> — 列表中显示了当前地图可用的所有纹理缩略图。默认地图通常自带草地、荒地、岩石等基础纹理。你可以用鼠标左键点击选中一个纹理，选中后该纹理会高亮显示[^2]。</p></li><li><p><strong>使用画笔涂抹地形</strong> — 选中纹理后，在右侧地图区域按住鼠标左键拖动即可涂抹该纹理。按住鼠标的时间越长，纹理覆盖面积越大。你可以通过调整工具栏下方的&quot;画笔大小（Brush Size）&quot;来控制每次涂抹的范围[^3]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：在涂抹大面积区域时，建议先选择较大的画笔尺寸快速覆盖，再用小画笔修补边缘细节，这样效率更高。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易忽略的是——地形纹理不是&quot;画&quot;上去的装饰，而是实际改变了地形的物理属性。比如用&quot;深水&quot;纹理涂抹的区域单位无法通行，用&quot;悬崖&quot;纹理会改变地形高度。涂抹前要明确你想要的地形效果。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够打开地形纹理面板、选择不同的纹理类型，并用画笔在地图上涂抹各种地形。掌握这些基础操作后，你的地图就不再是单调的绿色平面，而是开始有了地形的变化和视觉层次。建议你打开世界编辑器，新建一张空地图，实际操作练习一下这些步骤！</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://worldofwarcraft.blizzard.com/" target="_blank" rel="noreferrer">World of Warcraft</a> — accessed 2026-05-07 [^2]: <a href="https://www.youtube.com/watch?v=E1COCnMUIhQ" target="_blank" rel="noreferrer">Texture Animation | Import Any Video Into Blender With... - YouTube</a> — accessed 2026-05-07 [^3]: <a href="https://bentleysystems.service-now.com/community" target="_blank" rel="noreferrer">Bentley Community - Communities</a> — accessed 2026-05-07</p>',11)])])}const m=t(n,[["render",i]]);export{p as __pageData,m as default};
